//#region src/tools/mergeRefs.ts
/**
* @param refs Refs to merge.
* @returns Merged ref.
*/
const mergeRefs = (...refs) => {
	return (value) => {
		refs.forEach((ref) => {
			if (!ref) return;
			if (typeof ref === "function") ref(value);
			else if (typeof ref === "object" && "current" in ref) ref.current = value;
		});
	};
};

//#endregion
export { mergeRefs };